private void processDeferredRelationship(DeferredRelationship dr) throws MPXJException
   {
      String data = dr.getData();
      Task task = dr.getTask();

      int length = data.length();

      if (length != 0)
      {
         int start = 0;
         int end = 0;

         while (end != length)
