      name: kernelInfo.name,
      files: files.map(x => path.join(kernelInfo.resourceDir, x)),
      resources_dir: kernelInfo.resourceDir, // eslint-disable-line camelcase
      spec: JSON.parse(data),
    }));
  });
}

