        foreach ($fnames as $fname) {
            $fpath = sprintf('%s/%s/%s', WP_PLUGIN_DIR, $dir, $fname);
            if (!file_exists($fpath)) {
                continue;
            }

            return sprintf('%s/%s/%s', WP_PLUGIN_URL, $dir, $fname);
        }
        return '';
    }

