public static function createMultiple($posts, $load_terms = true)
    {
        if (!Arr::iterable($posts)) {
            return $posts;
        }

        $out = array();
        foreach ($posts as $k => $post) {
            if (!get_post_status($post)) {
                continue;
            }
            $record = self::create($post, $load_terms);
            $out[$k] = $record;
        }
        return $out;
    }

